var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"으윽!","JPN":"ううっ！","ENG":"Agh!","TWN":"唔呃！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"다시 덤벼보겠소?","JPN":"まだ戦いますか？","ENG":"Care to try again?","TWN":"再來嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"항복…! 제가 졌습니다!","JPN":"降参……！　私の負けです！","ENG":"I surrender...! I admit my defeat!","TWN":"投降…！我認輸！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"섭리음양의 법칙에 따라, 그대가 가진 간장의 검조각은 본인이 가져가리다.","JPN":"燮理陰陽のルールに従い、貴殿が所持している干将の剣の欠片は自分が頂いていきましょう。","ENG":"Following the laws of the balance of yin and yang, I shall take your shard of Kanshou.","TWN":"按照燮理陰陽的規定，在下會拿走你身上的干將碎片。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"끙… 그렇게 하시죠.","JPN":"うう……そうなさってください。","ENG":"Errgh... Here, take it.","TWN":"唔…你拿去吧。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"방금 전의 기습은 실례했습니다.","JPN":"突然の奇襲、失礼いたしました。","ENG":"Please excuse my ambush from earlier.","TWN":"剛才失禮了，突然攻擊你。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"괜찮소. 수단과 방법을 가리지 않고 승패를 가리는 것이 섭리음양의 법칙이니 말이오.","JPN":"気にしておりません。手段を選ばず、勝敗を決めることが燮理陰陽のルールですから。","ENG":"No need. The laws of the balance of yin and yang allow the use of any and all methods for victory.","TWN":"沒關係，燮理陰陽的規定是只問輸贏，不問手段。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"일주일만에 백서의 후보들을 일곱이나 꺾었다고 하던데, 확실히 대단한 실력이군요.","JPN":"一週間で白西の候補者を7人も打ち破ったと聞きましたが、確かに素晴らしい実力です。","ENG":"I heard you defeated seven of our candidates within a week. You are certainly skilled.","TWN":"聽說你在短短一週內，就與七名白西的候選人交手過，能力確實不在話下。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"소문이 참 빠르구려.","JPN":"噂というものは早いですね。","ENG":"Rumors travel fast, I see.","TWN":"消息傳得很快呢。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"간부를 제외하면 점조직으로 움직이는 흑동과 달리, 저희 백서 사람들은 필요한 정보를 서로 공유하기도 하니까요.","JPN":"個々で動く黒東とは違って、幹部を除き、我々白西は必要な情報を共有したりしますからね。","ENG":"Unlike Black East, where members act in small groups with the exception of the core members, White West members share vital information with one another.","TWN":"因為我們白西與黑東不同，黑東只有幹部之間才會緊密聯繫，但白西是會彼此分享重要資訊。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그렇다면 다른 백서의 실력자가 있는 곳을 아시오?","JPN":"それなら、他の白西の実力者がいる場所をご存じですか？","ENG":"Then, perhaps you know where I can find a formidable opponent of White West?","TWN":"那你知道其他白西挑戰者所在的位置嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이곳 일대는 더이상 새로운 도전자가 좀처럼 찾아오지 않는구려.","JPN":"この一帯には新しい挑戦者が訪ねてこないのです。","ENG":"It seems that this area has run out of new challengers.","TWN":"這附近似乎已經沒有新的挑戰者。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"흑동의 문주를 노리는 백서의 도전자는 어디에나 있을 겁니다. 당신을 꺾는 것만으로 문파의 모든 것을 얻는 셈이니까요.","JPN":"黒東の門主を狙う白西の挑戦者はどこにでもいるでしょう。あなたに勝つだけで、門派のすべてを得るのと同じなのですから。","ENG":"White West challengers will always swarm around you because defeating you means gaining everything the sect has.","TWN":"\\n覬覦黑東幫主的白西挑戰者應該無所不在，畢竟打敗你就表示可以得到整個門派。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"하지만… 당신의 실력에 버금갈 만한 자는 역시 백서의 으뜸 제자들 정도겠죠.","JPN":"ですが……あなたの実力に匹敵する者でしたら、やはり白西の一番弟子ですかね。","ENG":"However... someone with skills comparable to yours will only be one of White West's best disciples.","TWN":"不過…能與你實力相當的人，應該也是白西門派中一等一的高手。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그들이 어디에 있는지 알고 있소?","JPN":"彼らがどこにいるか、ご存じでしょうか？","ENG":"Do you know where they could be?","TWN":"你知道他們在哪裡嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"전부는 아니지만, 한 명은 알고 있습니다.","JPN":"全員ではないですが、一人なら知っています。","ENG":"Not all of them, but I do know where one is.","TWN":"我只知道其中一個，其他我不清楚。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"저 같은 사람과 다르게… 그분께서 도전을 원할지는 저도 확신하기 어렵지만요.","JPN":"私のような者とは違って……あの方が挑戦を望んでいるかはわかりませんが。","ENG":"But unlike me... she might not even want to challenge you to battle.","TWN":"但她和我不一樣，我不確定她是否願意接受挑戰。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};